CREATE TRIGGER [dbo].[Supplier_History]ON [dbo].[Supplier]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.SupplierId IS NOT NULL AND d.SupplierId IS NULL THEN 'I' 		WHEN i.SupplierId IS NOT NULL AND d.SupplierId IS NOT NULL THEN 'U' 		WHEN i.SupplierId IS NULL AND d.SupplierId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.SupplierId = d.SupplierId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Supplier([SupplierId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [SupplierId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Supplier([SupplierId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [SupplierId], [Name], [Address], [PostalCode], [City], [StateOrProvince], [Country], [PhoneNumber], [EmailAddress], [ContactName], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND